// Help entries for the Signal Processing Toolbox, extracted from signal.ts.
// Keyed by function name; consumed via ToolboxModule.help (see tb/types.ts).
import type { HelpEntry } from './types';

export const HELP_SIGNAL: Record<string, HelpEntry | string> = {
    cheby2: { summary: 'Designs an order n lowpass digital Chebyshev Type II filter with normalized stopband edge frequency Ws and stopband attenuation Rs dB.', syntax: ['[b,a] = cheby2(n,Rs,Ws)', '[b,a] = cheby2(n,Rs,Ws,ftype)'], seealso: ['cheb2ap', 'cheb2ord', 'butter', 'cheby1', 'ellip'], description: ['[b,a] = cheby2(n,Rs,Ws) designs an nth-order lowpass digital Chebyshev Type II filter with normalized stopband edge frequency Ws and Rs decibels of stopband attenuation down from the peak passband value. The cheby2 function returns the numerator and denominator coefficients of the filter transfer function.', '[b,a] = cheby2(n,Rs,Ws,fType) designs a lowpass, highpass, bandpass, or bandstop digital Chebyshev Type II filter, depending on the value of fType and the number of elements of Ws. The resulting bandpass and bandstop designs are of order 2n.', 'Note', 'You might encounter numerical instabilities when designing IIR filters with transfer functions for orders as low as 4. See Transfer Functions and CTF for more information about numerical issues that affect forming the transfer function.', '[z,p,k] = cheby2(___) designs a digital Chebyshev Type II filter and returns its zeros, poles, and gain. This syntax can include any of the input arguments in previous syntaxes.'] },
    ellip: { summary: 'Designs an order n lowpass digital elliptic filter with normalized passband edge frequency Wp, Rp dB of passband ripple, and Rs dB of stopband attenuation.', syntax: ['[b,a] = ellip(n,Rp,Rs,Wp)', '[b,a] = ellip(n,Rp,Rs,Wp,ftype)'], seealso: ['ellipap', 'ellipord', 'butter', 'cheby1', 'cheby2'], description: ['[b,a] = ellip(n,Rp,Rs,Wp) designs an nth-order lowpass digital elliptic filter with normalized passband edge frequency Wp. The resulting filter has Rp decibels of peak-to-peak passband ripple and Rs decibels of stopband attenuation relative to the peak passband value. The ellip function returns the numerator and denominator coefficients of the filter transfer function.', '[b,a] = ellip(n,Rp,Rs,Wp,fType) designs a lowpass, highpass, bandpass, or bandstop digital elliptic filter, depending on the value of fType and the number of elements of Wp. The resulting bandpass and bandstop designs are of order 2n.', 'Note', 'You might encounter numerical instabilities when designing IIR filters with transfer functions for orders as low as 4. See Transfer Functions and CTF for more information about numerical issues that affect forming the transfer function.', '[z,p,k] = ellip(___) designs a digital elliptic filter and returns its zeros, poles, and gain. This syntax can include any of the input arguments in previous syntaxes.'] },
    fir2: { summary: 'Returns an order n FIR filter with frequency-magnitude characteristics specified in the vectors f and m, designed by inverse Fourier transform and windowing.', syntax: ['b = fir2(n,f,m)', 'b = fir2(n,f,m,npt)', 'b = fir2(n,f,m,npt,lap)', 'b = fir2(___,window)'], seealso: ['fir1', 'firls', 'firpm', 'cfirpm'], description: ['b = fir2(n,f,m) returns an nth-order FIR filter with frequency- magnitude characteristics specified in the vectors f and m. The function linearly interpolates the desired frequency response onto a dense grid and then uses the inverse Fourier transform and a Hamming window to obtain the filter coefficients.', 'b = fir2(n,f,m,npt,lap) specifies npt, the number of points in the interpolation grid, and lap, the length of the region that fir2 inserts around duplicate frequency points which specify steps in the frequency response.', 'b = fir2(___,window) specifies a window vector to use in the design in addition to any input arguments from previous syntaxes.', 'Note: Use fir1 for window-based standard lowpass, bandpass, highpass, bandstop, and multiband configurations.'] },
    buttord: { summary: 'Returns the lowest order n of the digital Butterworth filter with normalized passband edge Wp, stopband edge Ws, Rp dB passband ripple, and Rs dB stopband attenuation, plus the Butterworth natural frequency Wn.', syntax: ['[n,Wn] = buttord(Wp,Ws,Rp,Rs)'], seealso: ['butter', 'cheb1ord', 'cheb2ord', 'ellipord'], description: ['[n,Wn] = buttord(Wp,Ws,Rp,Rs) returns the lowest order, n, of the digital Butterworth filter with no more than Rp dB of passband ripple and at least Rs dB of attenuation in the stopband. Wp and Ws are respectively the passband and stopband edge frequencies of the filter, normalized from 0 to 1, where 1 corresponds to _π_ rad/sample. The scalar (or vector) of corresponding cutoff frequencies, Wn, is also returned. To design a Butterworth filter, use the output arguments n and Wn as inputs to butter.', '[n,Wn] = buttord(Wp,Ws,Rp,Rs,\'s\') finds the minimum order n and cutoff frequencies Wn for an analog Butterworth filter. Specify the frequencies Wp and Ws in radians per second. The passband or the stopband can be infinite.'] },
    cheb1ord: { summary: 'Returns the lowest order n of the Chebyshev Type I filter that loses no more than Rp dB in the passband and has at least Rs dB of attenuation in the stopband, with cutoff Wn.', syntax: ['[n,Wn] = cheb1ord(Wp,Ws,Rp,Rs)'], seealso: ['cheby1', 'buttord', 'cheb2ord', 'ellipord'], description: ['[n,Wp] = cheb1ord(Wp,Ws,Rp,Rs) returns the lowest order n of the Chebyshev Type I filter that loses no more than Rp dB in the passband and has at least Rs dB of attenuation in the stopband. The scalar (or vector) of corresponding cutoff frequencies Wp is also returned.', '[n,Wp] = cheb1ord(Wp,Ws,Rp,Rs,\'s\') designs a lowpass, highpass, bandpass, or bandstop analog Chebyshev Type I filter with cutoff angular frequencies Wp.'] },
    cheb2ord: { summary: 'Returns the lowest order n of the Chebyshev Type II filter that loses no more than Rp dB in the passband and has at least Rs dB of attenuation in the stopband, with cutoff Wn.', syntax: ['[n,Wn] = cheb2ord(Wp,Ws,Rp,Rs)'], seealso: ['cheby2', 'buttord', 'cheb1ord', 'ellipord'], description: ['[n,Ws] = cheb2ord(Wp,Ws,Rp,Rs) returns the lowest order n of the Chebyshev Type II filter that loses no more than Rp dB in the passband and has at least Rs dB of attenuation in the stopband. The scalar (or vector) of corresponding cutoff frequencies Ws is also returned.', '[n,Ws] = cheb2ord(Wp,Ws,Rp,Rs,\'s\') designs a lowpass, highpass, bandpass, or bandstop analog Chebyshev Type II filter with cutoff angular frequencies Ws.'] },
    ellipord: { summary: 'Returns the lowest order n of the elliptic filter that loses no more than Rp dB in the passband and has at least Rs dB of attenuation in the stopband, with cutoff Wn.', syntax: ['[n,Wn] = ellipord(Wp,Ws,Rp,Rs)'], seealso: ['ellip', 'buttord', 'cheb1ord', 'cheb2ord'], description: ['[n,Wn] = ellipord(Wp,Ws,Rp,Rs) returns the lowest order, n, of the digital elliptic filter with no more than Rp dB of passband ripple and at least Rs dB of attenuation in the stopband. Wp and Ws, are respectively, the passband and stopband edge frequencies of the filter, normalized from 0 to 1, where 1 corresponds to _π_ rad/sample. The scalar (or vector) of corresponding cutoff frequencies, Wn, is also returned. To design an elliptic filter, use the output arguments n and Wn as inputs to ellip.', '[n,Wn] = ellipord(Wp,Ws,Rp,Rs,\'s\') finds the minimum order n and cutoff frequencies Wn for an analog elliptic filter. Specify the frequencies Wp and Ws in radians per second. The passband or the stopband can be infinite.'] },
    lin2mu: { summary: 'Convert linear to mu-law compressed values (G.711)', syntax: ['y = lin2mu(x)'], seealso: ['mu2lin'] },
    xcorr2: { summary: '2-D cross-correlation', syntax: ['c = xcorr2(a,b)', 'c = xcorr2(a)'], seealso: ['xcorr', 'conv2'], description: ['c = xcorr2(a,b) returns the cross-correlation of matrices a and b with no scaling. xcorr2 is the two-dimensional version of xcorr.', 'c = xcorr2(a) is the autocorrelation matrix of input matrix a. This syntax is equivalent to xcorr2(a,a).'] },
    qmf: { summary: 'Quadrature mirror filter', syntax: ['y = qmf(x)', 'y = qmf(x,p)'], seealso: ['wfilters'] },
    lar2rc: { summary: 'Returns the reflection coefficients, k, from the log area ratio parameters g.', syntax: ['k = lar2rc(g)'], seealso: ['ac2rc', 'is2rc', 'poly2rc', 'rc2lar'], description: ['k = lar2rc(g) returns the reflection coefficients, k, from the log area ratio parameters g.'] },
    is2rc: { summary: 'Returns the reflection coefficients, k, from the inverse sine parameters isin.', syntax: ['k = is2rc(isin)'], seealso: ['ac2rc', 'lar2rc', 'poly2rc', 'rc2is'], description: ['k = is2rc(isin) returns the reflection coefficients, k, from the inverse sine parameters isin.'] },
    vco: { summary: 'Creates a signal that oscillates at a frequency determined by the real input vector or matrix x with sample rate Fs.', syntax: ['y = vco(x,Fc,Fs)', 'y = vco(x,[Fmin Fmax],Fs)'], seealso: ['demod', 'modulate'], description: ['y = vco(x,Fc,Fs) creates a signal that oscillates at a frequency determined by the real input vector or matrix x with sample rate Fs. If x is a matrix, vco produces a matrix whose columns oscillate according to the columns of x.', 'y = vco(x,[Fmin Fmax],Fs) scales the frequency modulation range so that ±1 values of x yield oscillations of Fmin Hz and Fmax Hz, respectively.'] },
    diric: { summary: 'Returns the Dirichlet Function of degree n evaluated at the elements of the input array x.', syntax: ['y = diric(x,n)'], seealso: ['cos', 'gauspuls', 'pulstran', 'rectpuls', 'sawtooth'], description: ['y = diric(x,n) returns the Dirichlet Function of degree n evaluated at the elements of the input array x.'] },
    uencode: { summary: 'Quantizes the entries in a multidimensional array of floating-point numbers x in the range [-1, 1], and encodes them as integers using 2n-level quantization.', syntax: ['y = uencode(x,n)', 'y = uencode(x,n,v)', 'y = uencode(x,n,v,outputSign)'], seealso: ['udecode'], description: ['y = uencode(x,n) quantizes the entries in a multidimensional array of floating-point numbers x in the range [-1, 1], and encodes them as integers using 2 _n_ -level quantization. The elements of the output y are unsigned integers with magnitudes in the range [0, 2 _n_ – 1].', 'y = uencode(x,n,v) allows the input x to have entries with floating-point values in the range [-v,v] before saturating them.', 'y = uencode(x,n,v,outputSign) specifies the option outputSign to generate signed or unsigned integer outputs.'] },
    rectwin: { summary: 'Returns a rectangular window of length L.', syntax: ['w = rectwin(L)', 'w = rectwin(L,typeName)'], description: ['w = rectwin(L) returns a rectangular window of length L.', 'w = rectwin(L,typeName) specifies the option to return the window w with single or double precision._(since R2026a)_'] },
    blackman: { summary: 'Returns an L-point symmetric Blackman window.', syntax: ['w = blackman(L)', 'w = blackman(L,sflag)', 'w = blackman( ___ ,typeName)'], description: ['w = blackman(L) returns an L-point symmetric Blackman window.', 'w = blackman(L,sflag) returns a Blackman window using the window sampling method specified by sflag.', 'w = blackman(___,typeName) specifies the option to return the window w with single or double precision for any of the previous syntaxes._(since R2024b)_'] },
    flattopwin: { summary: 'Returns an L-point symmetric flat top window', syntax: ['w = flattopwin(L)', 'w = flattopwin(L,sflag)', 'w = flattopwin( ___ ,typeName)'], description: ['w = flattopwin(L) returns an L-point symmetric flat top window', 'w = flattopwin(L,sflag) returns an L-point symmetric flat top window using the window sampling method specified by sflag.', 'w = flattopwin(___,typeName) specifies the option to return the window w with single or double precision for any of the previous syntaxes._(since R2024b)_'] },
    gausswin: { summary: 'Returns an L-point Gaussian window.', syntax: ['w = gausswin(L)', 'w = gausswin(L,alpha)', 'w = gausswin( ___ ,typeName)'], description: ['w = gausswin(L) returns an L-point Gaussian window.', 'w = gausswin(L,alpha) returns an L-point Gaussian window with width factor alpha.', 'Note', 'If the window appears to be clipped, increase L, the number of points.', 'w = gausswin(___,typeName) specifies the option to return the window w with single or double precision for any of the previous syntaxes._(since R2026a)_'] },
    parzenwin: { summary: 'Returns the L-point Parzen (de la Vallée Poussin) window.', syntax: ['w = parzenwin(L)', 'w = parzenwin(L,typeName)'], description: ['w = parzenwin(L) returns the L-point Parzen (de la Vallée Poussin) window.', 'w = parzenwin(L,typeName) specifies the option to return the window w with single or double precision._(since R2024b)_'] },
    chebwin: { summary: 'Returns an L-point Chebyshev window.', syntax: ['w = chebwin(L)', 'w = chebwin(L,r)', 'w = chebwin( ___ ,typeName)'], description: ['w = chebwin(L) returns an L-point Chebyshev window.', 'w = chebwin(L,r) returns an L-point Chebyshev window using sidelobe magnitude factor r dB.', 'w = chebwin(___,typeName) specifies the option to return the window w with single or double precision for any of the previous syntaxes._(since R2024b)_'] },
    edr: { summary: 'Returns the Edit Distance on Real Signals between sequences x and y.', syntax: ['dist = edr(x,y,tol)', '[ ___ ] = edr(x,y,maxsamp)', '[ ___ ] = edr( ___ ,metric)', 'edr( ___ )'], seealso: ['alignsignals', 'dtw', 'finddelay', 'findsignal', 'xcorr'], description: ['dist = edr(x,y,tol) returns the Edit Distance on Real Signals between sequences x and y. edr returns the minimum number of elements that must be removed from x, y, or both x and y, so that the sum of Euclidean distances between the remaining signal elements lies within the specified tolerance, tol.', '[dist,ix,iy] = edr(x,y,tol) returns the warping path such that x(ix) and y(iy) have the smallest possible dist between them. When x and y are matrices, ix and iy are such that x(:,ix) and y(:,iy) are minimally separated.', '[___] = edr(x,y,maxsamp) restricts the insertion operations so that the warping path remains within maxsamp samples of a straight-line fit between x and y. This syntax returns any of the output arguments of previous syntaxes.', '[___] = edr(___,metric) specifies the distance metric to use in addition to any of the input arguments in previous syntaxes. metric can be one of \'euclidean\', \'absolute\', \'squared\', or \'symmkl\'.', 'edr(___) without output arguments plots the original and aligned signals.'] },
    statelevels: { summary: 'Estimates the low and high state levels in the bilevel waveform x using the histogram method.', syntax: ['levels = statelevels(x)', 'levels = statelevels(x,nbins)', 'levels = statelevels(x,nbins,method)', 'levels = statelevels(x,nbins,method,bounds)'], seealso: ['midcross', 'overshoot', 'risetime', 'undershoot'], description: ['levels = statelevels(x) estimates the low and high state levels in the bilevel waveform x using the histogram method. For more information, see Algorithms.', 'levels = statelevels(x,nbins) specifies the number of bins to use in the histogram as a positive scalar.', 'levels = statelevels(x,nbins,method) estimates state levels using the mean or mode of the subhistograms.', 'levels = statelevels(x,nbins,method,bounds) specifies the lower and upper bounds of the histogram in the two-element real row vector bounds. statelevels ignores any values of x that lie outside these bounds when it computes the histogram.', '[levels,histogram] = statelevels(___) returns the histogram of the values in x.'] },
    pulsewidth: { summary: 'Returns the time differences between the mid-reference level instants of the initial and final transitions of each positive-polarity pulse in the input bilevel waveform.', syntax: ['w = pulsewidth(x)', 'w = pulsewidth(x,fs)', 'w = pulsewidth(x,t)', 'W = pulsewidth( ___ ,Name,Value)'], seealso: ['dutycycle', 'pulseperiod', 'pulsesep', 'statelevels'], description: ['w = pulsewidth(x) returns the time differences between the mid-reference level instants of the initial and final transitions of each positive-polarity pulse in the input bilevel waveform.', 'w = pulsewidth(x,fs) specifies the sample rate fs in hertz. The first sample in the waveform corresponds to t = 0.', 'w = pulsewidth(x,t) specifies the sample instants t.', '[w,initcross] = pulsewidth(___) returns initcross, the mid-reference level instants of the initial transition of each pulse. You can specify an input combination from any of the previous syntaxes.', '[w,initcross,finalcross] = pulsewidth(___) returns finalcross, the mid-reference level instants of the final transition of each pulse.'] },
    risetime: { summary: 'Returns a vector, r, containing the time each transition of the input bilevel waveform, x, takes to cross from the 10% to 90% reference levels.', syntax: ['r = risetime(x)', 'r = risetime(x,fs)', 'r = risetime(x,t)', '[ ___ ] = risetime( ___ ,Name=Value)'], seealso: ['falltime', 'slewrate', 'statelevels'], description: ['r = risetime(x) returns a vector, r, containing the time each transition of the input bilevel waveform, x, takes to cross from the 10% to 90% reference levels. To determine the transitions, risetime estimates the state levels of the input waveform by a histogram method. risetime identifies all regions that cross the upper-state boundary of the low state and the lower-state boundary of the high state. The low-state and high-state boundaries are expressed as the state level plus or minus a multiple of the difference between the state levels. See State-Level Tolerances. Because risetime uses interpolation, r can contain values that do not correspond to sampling instants of the bilevel waveform, x.', 'r = risetime(x,fs) specifies the sample rate in hertz. The sample rate determines the sample instants corresponding to the elements in x. The first sample instant in x corresponds to _t_ = 0. Because risetime uses interpolation, r can contain values that do not correspond to sampling instants of the bilevel waveform, x.', 'r = risetime(x,t) specifies the sample instants, t, as a vector with the same number of elements as x.', '[r,lt,ut] = risetime(___) returns vectors lt and ut whose elements correspond to the time instants where x crosses the lower- and upper-percent reference levels. You can use this output syntax with any of the previous input syntaxes.', '[r,lt,ut,ll,ul] = risetime(___) returns the levels, ll and ul, that correspond to the lower- and upper-percent reference levels.'] },
    overshoot: { summary: 'Returns overshoots expressed as a percentage of the difference between the low- and high-state levels in the input bilevel waveform.', syntax: ['os = overshoot(x)', 'os = overshoot(x,fs)', 'os = overshoot(x,t)', '[ ___ ] = overshoot( ___ ,Name,Value)'], seealso: ['settlingtime', 'statelevels'], description: ['os = overshoot(x) returns overshoots expressed as a percentage of the difference between the low- and high-state levels in the input bilevel waveform. The values in os correspond to the greatest absolute deviations that are greater than the final state levels of each transition.', 'os = overshoot(x,fs) specifies the sample rate fs in hertz.', 'os = overshoot(x,t) specifies the sample instants t.', '[os,oslev,osinst] = overshoot(___) returns the levels oslev and sample instants osinst of the overshoots for each transition. You can specify an input combination from any of the previous syntaxes.', '[___] = overshoot(___,Name,Value) specifies additional options using one or more Name,Value arguments. You can use any of the output combinations from previous syntaxes.'] },
    settlingtime: { summary: 'Returns the time from the mid-reference level instant to the time instant each transition enters and remains within a 2% tolerance region of the final state over the duration d.', syntax: ['s = settlingtime(x,d)', 's = settlingtime(x,Fs,d)', 's = settlingtime(x,t,d)', 'settlingtime( ___ )'], seealso: ['falltime', 'midcross', 'pulsewidth', 'risetime', 'statelevels'], description: ['s = settlingtime(x,d) returns the time from the mid-reference level instant to the time instant each transition enters and remains within a 2% tolerance region of the final state over the duration d. To determine the transitions, the settlingtime function estimates the state levels of the input waveform by a histogram method and identifies all regions that cross the upper-state boundary of the low state and the lower-state boundary of the high state.', 'Note', 'If for any transition, the level of the waveform does not remain within the lower and upper tolerance boundaries, the requested duration is not present, or an intervening transition is detected, settlingtime marks the corresponding element in s as NaN. For cases in which settlingtime returns a NaN, see Settle Seek Duration.', 's = settlingtime(x,Fs,d) specifies the sample rate Fs.', 's = settlingtime(x,t,d) specifies the sample instants t.'] },
    periodogram: { summary: 'Returns the periodogram power spectral density (PSD) estimate of the signal x.', syntax: ['pxx = periodogram(x)', '[pxx,f] = periodogram(x,win,freqSpec)', '[pxx,f] = periodogram(x,win,freqSpec,Fs)', '[pxx,f] = periodogram( ___ ,freqRange,spectrumType)'], description: ['pxx = periodogram(x) returns the periodogram power spectral density (PSD) estimate of the signal x. The function treats the column of x as independent channels.', '[pxx,f] = periodogram(x,win,freqSpec) returns the periodogram PSD estimate of the signal x and the frequencies f (rad/sample), where the periodogram function:', '* Uses win to divide the signal into segments and windows them.', '* Computes the discrete Fourier transform (DFT) over the number of DFT points or at the frequencies specified in freqSpec.', 'To use default values for any of these input arguments, specify them as empty, [].'] },
    stft: { summary: 'Returns the Short-Time Fourier Transform (STFT) of x.', syntax: ['s = stft(x)', 's = stft(x,fs)', 's = stft(x,ts)', 's = stft( ___ ,Name=Value)'], description: ['s = stft(x) returns the Short-Time Fourier Transform (STFT) of x.', 's = stft(x,fs) returns the STFT of x using sample rate fs.', 's = stft(x,ts) returns the STFT of x using sample time ts.', 's = stft(___,Name=Value) specifies additional options using name-value arguments. Options include the FFT window and length. These arguments can be added to any of the previous input syntaxes.', '[s,f] = stft(___) returns the frequencies f at which the STFT is evaluated.'] },
    rectpuls: { summary: 'Returns a continuous, aperiodic, unit-height rectangular pulse at the sample times indicated in array t, centered about t = 0.', syntax: ['y = rectpuls(t)', 'y = rectpuls(t,w)'], seealso: ['chirp', 'cos', 'diric', 'gauspuls', 'pulstran'], description: ['y = rectpuls(t) returns a continuous, aperiodic, unit-height rectangular pulse at the sample times indicated in array t, centered about t = 0.', 'y = rectpuls(t,w) generates a rectangle of width w.'] },
    upsample: { summary: 'Increases the sample rate of x by inserting n – 1 zeros between samples.', syntax: ['y = upsample(x,n)', 'y = upsample(x,n,phase)'], seealso: ['decimate', 'downsample', 'interp', 'interp1', 'resample'], description: ['y = upsample(x,n) increases the sample rate of x by inserting n – 1 zeros between samples. If x is a matrix, the function treats each column as a separate sequence.', 'y = upsample(x,n,phase) specifies the number of samples by which to offset the upsampled sequence.'] },
    fwht: { summary: 'Returns the coefficients of the discrete Walsh-Hadamard transform of the input x.', syntax: ['y = fwht(x)', 'y = fwht(x,n)', 'y = fwht(x,n,ordering)'], seealso: ['ifwht', 'dct', 'idct', 'fft', 'ifft'], description: ['y = fwht(x) returns the coefficients of the discrete Walsh-Hadamard transform of the input x.', 'y = fwht(x,n) returns the n-point discrete Walsh-Hadamard transform.', 'y = fwht(x,n,ordering) specifies the ordering to use for the returned Walsh-Hadamard transform coefficients.'] },
    rceps: { summary: 'Returns both the real cepstrum y and a minimum phase reconstructed version ym of the input sequence.', syntax: ['[y,ym] = rceps(x)'], seealso: ['cceps', 'fft', 'hilbert', 'icceps', 'unwrap'], description: ['[y,ym] = rceps(x) returns both the real cepstrum y and a minimum phase reconstructed version ym of the input sequence.'] },
    meanfreq: { summary: 'Estimates the mean normalized frequency, freq, of the power spectrum of a time-domain signal, x.', syntax: ['freq = meanfreq(x)', 'freq = meanfreq(x,Fs)', 'freq = meanfreq(pxx,f)', 'freq = meanfreq(sxx,f,rbw)'], seealso: ['findpeaks', 'medfreq', 'periodogram', 'plomb', 'pwelch'], description: ['freq = meanfreq(x) estimates the mean normalized frequency, freq, of the power spectrum of a time-domain signal, x. To compute the power spectrum, meanfreq uses the periodogram function with a rectangular window and a number of DFT points equal to the length of x. If x is a matrix, the function computes the mean frequency of each column of x independently.', 'freq = meanfreq(x,Fs) estimates the mean frequency in terms of the sample rate, Fs.', 'freq = meanfreq(pxx,f) returns the mean frequency of a power spectral density (PSD) estimate, pxx. The frequencies, f, correspond to the estimates in pxx.', 'freq = meanfreq(sxx,f,rbw) returns the mean frequency of a power spectrum estimate, sxx, with resolution bandwidth rbw.', 'freq = meanfreq(___,freqRange) specifies the frequency interval over which to compute the mean frequency. This syntax can include any combination of input arguments from previous syntaxes, as long as the second input argument is either Fs or f. If the second input is passed as empty, normalized frequency will be assumed. The default value for freqRange is the entire bandwidth of the input signal.'] },
    powerbw: { summary: 'Returns the 3 dB (half-power) bandwidth bw of the input signal x.', syntax: ['bw = powerbw(x)', 'bw = powerbw(x,Fs)', 'bw = powerbw(pxx,f)', 'bw = powerbw(sxx,f,rbw)'], seealso: ['bandpower', 'obw', 'periodogram', 'plomb', 'pwelch'], description: ['bw = powerbw(x) returns the 3 dB (half-power) bandwidth bw of the input signal x. The function obtains the 3 dB bandwidth from the periodogram of the signal x.', 'bw = powerbw(x,Fs) returns the 3 dB bandwidth in terms of the sample rate Fs.', 'bw = powerbw(pxx,f) returns the 3 dB bandwidth of the power spectral density (PSD) estimate pxx. The frequencies f correspond to the estimates in pxx.', 'bw = powerbw(sxx,f,rbw) computes the 3 dB bandwidth of the power spectrum estimate sxx. The frequencies f correspond to the estimates in sxx. The function uses the resolution bandwidth rbw to integrate each power estimate.', 'bw = powerbw(___,freqLims,r) specifies the frequency interval over which to compute the reference level. This syntax can include any combination of input arguments from previous syntaxes, as long as the second input argument is either Fs or f. If the second input is passed as empty, powerbw assumes a normalized frequency. The function computes the difference in frequency between the points where the spectrum drops below the reference level by r dB or reaches an endpoint.'] },
    mag2db: { summary: 'Expresses in decibels (dB) the magnitude measurements specified in y.', syntax: ['ydb = mag2db(y)'], seealso: ['db', 'db2mag', 'db2pow', 'pow2db'], description: ['ydb = mag2db(y) expresses in decibels (dB) the magnitude measurements specified in y. The relationship between magnitude and decibels is ydb = 20 log10(y).'] },
    sinc: { summary: 'Returns an array, y, whose elements are the sinc of the elements of the input, x.', syntax: ['y = sinc(x)'], seealso: ['chirp', 'diric', 'gauspuls', 'pulstran', 'rectpuls'], description: ['y = sinc(x) returns an array, y, whose elements are the sinc of the elements of the input, x. The output y is the same size as x.'] },
    freqz: { summary: 'Returns the frequency response of the specified digital filter.', syntax: ['[h,w] = freqz(B,A,"ctf",n)', '[h,w] = freqz({B,A,g},"ctf",n)', '[h,w] = freqz(d,n)', '[h,w] = freqz(sos,n)'], description: ['[h,w] = freqz(b,a,n) returns the frequency response of the specified digital filter. Specify a digital filter with numerator coefficients b and denominator coefficients a. The function returns the n-point frequency response vector in h and the corresponding angular frequency vector w.', '[h,w] = freqz(B,A,"ctf",n) returns the n-point frequency response of the digital filter represented as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A._(since R2024b)_', '[h,w] = freqz({B,A,g},"ctf",n) returns the n-point frequency response of the digital filter in CTF format. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', '[h,w] = freqz(d,n) returns the n-point complex frequency response for the digital filter d.', '[h,w] = freqz(sos,n) returns the n-point complex frequency response corresponding to the second- order sections matrix sos.'] },
    goertzel: { summary: 'Returns the discrete-time Fourier transform (DTFT) of the input array data using a second-order Goertzel algorithm.', syntax: ['dft = goertzel(data)', 'dft = goertzel(data,findx)', 'dft = goertzel(data,findx,dim)'], seealso: ['czt', 'fft'], description: ['dft = goertzel(data) returns the discrete-time Fourier transform (DTFT) of the input array data using a second-order Goertzel algorithm. If data has more than one dimension, then goertzel operates along the first array dimension with size greater than 1. For more information, see Algorithms.', 'dft = goertzel(data,findx) returns the DTFT for the frequency indices specified in findx as a vector of integers or nonintegers.', 'dft = goertzel(data,findx,dim) computes the DTFT along dimension dim. To input a dimension and use the default value of findx, specify the second argument as empty, [].'] },
    levinson: { summary: 'Returns the coefficients of an autoregressive linear process of order n that has r as its autocorrelation sequence.', syntax: ['a = levinson(r,n)', '[a,e,k] = levinson( ___ )'], seealso: ['lpc', 'prony', 'rlevinson', 'schurrc', 'stmcb'], description: ['a = levinson(r,n) returns the coefficients of an autoregressive linear process of order n that has r as its autocorrelation sequence.', '[a,e,k] = levinson(___) also returns the prediction error e, and the reflection coefficients, k.'] },
    poly2rc: { summary: 'Returns a vector k of lattice-structure reflection coefficients from a vector a of prediction filter coefficients.', syntax: ['k = poly2rc(a)', '[k,r0] = poly2rc(a,eFinal)'], seealso: ['ac2rc', 'latc2tf', 'latcfilt', 'poly2ac', 'rc2poly'], description: ['k = poly2rc(a) returns a vector k of lattice-structure reflection coefficients from a vector a of prediction filter coefficients.', '[k,r0] = poly2rc(a,eFinal) also returns the zero-lag autocorrelation, r0, based on the final prediction error eFinal.'] },
    ac2rc: { summary: 'Returns the reflection coefficients, k, from the autocorrelation sequence r.', syntax: ['[k,r0] = ac2rc(r)'], seealso: ['ac2poly', 'poly2rc', 'rc2ac'], description: ['[k,r0] = ac2rc(r) returns the reflection coefficients, k, from the autocorrelation sequence r. The ac2rc function also returns the zero-lag autocorrelation r0.'] },
    db: { summary: 'Converts the elements of x to decibels (dB).', syntax: ['dbOutput = db(x)', 'dbOutput = db(x,signalType)', 'dbOutput = db(x,R)', 'dbOutput = db(x,"voltage",R)'], seealso: ['db2mag', 'db2pow', 'mag2db', 'pow2db'], description: ['dbOutput = db(x) converts the elements of x to decibels (dB). This syntax assumes that x contains voltage measurements across a resistance of 1 Ω.', 'dbOutput = db(x,signalType) specifies the signal type represented by the elements of x as either "voltage" or "power".', 'dbOutput = db(x,R) specifies the resistance, R, for voltage measurements.', 'dbOutput = db(x,"voltage",R) is equivalent to db(x,R).'] },
    cell2sos: { summary: 'Generates a matrix sos containing the coefficients of the filter system described by the second-order section cell array cll.', syntax: ['sos = cell2sos(cll)', '[sos,g] = cell2sos(cll)'], seealso: ['sos2cell', 'tf2sos'], description: ['sos = cell2sos(cll) generates a matrix sos containing the coefficients of the filter system described by the second-order section cell array cll.', '[sos,g] = cell2sos(cll) also returns the scale gain g.'] },
    kaiserord: { summary: 'Returns a filter order n, normalized frequency band edges Wn, and a shape factor beta that specify a Kaiser window for use with the fir1 function.', syntax: ['[n,Wn,beta,ftype] = kaiserord(f,a,dev)', '[n,Wn,beta,ftype] = kaiserord(f,a,dev,fs)', 'c = kaiserord(f,a,dev,fs,"cell")'], seealso: ['fir1', 'kaiser', 'firpmord'], description: ['[n,Wn,beta,ftype] = kaiserord(f,a,dev) returns a filter order n, normalized frequency band edges Wn, and a shape factor beta that specify a Kaiser window for use with the fir1 function. To design an FIR filter b that approximately meets the specifications given by f, a, and dev, use b = fir1(n,Wn,kaiser(n+1,beta),ftype,"noscale").', '[n,Wn,beta,ftype] = kaiserord(f,a,dev,fs) uses a sample rate fs in Hz.', 'c = kaiserord(f,a,dev,fs,"cell") returns a cell array whose elements are the parameters to fir1.'] },
    sgolay: { summary: 'Designs a Savitzky-Golay FIR smoothing filter with polynomial order m and frame length fl.', syntax: ['b = sgolay(m,fl)', 'b = sgolay(m,fl,w)', '[b,g] = sgolay( ___ )'], description: ['b = sgolay(m,fl) designs a Savitzky-Golay FIR smoothing filter with polynomial order m and frame length fl.', 'b = sgolay(m,fl,w) specifies a weighting vector, w, which contains the real, positive-valued weights to be used during the least-squares minimization.', '[b,g] = sgolay(___) returns the matrix g of differentiation filters. You can use these output arguments with any of the previous input syntaxes.'] },
    buttap: { summary: 'Returns the poles and gain of an order n Butterworth analog lowpass filter prototype.', syntax: ['[z,p,k] = buttap(n)'], seealso: ['besselap', 'butter', 'cheb1ap', 'cheb2ap', 'ellipap'], description: ['[z,p,k] = buttap(n) returns the poles and gain of an order n Butterworth analog lowpass filter prototype.'] },
    filtfilt: { summary: 'Performs zero-phase digital filtering by processing the input data x in both the forward and reverse directions.', syntax: ['y = filtfilt(b,a,x)', 'y = filtfilt(sos,g,x)', 'y = filtfilt(d,x)', 'y = filtfilt(B,A,x,"ctf")'], seealso: ['ctffilt', 'designfilt', 'digitalFilter', 'fftfilt', 'filter'], description: ['y = filtfilt(b,a,x) performs zero-phase digital filtering by processing the input data x in both the forward and reverse directions. After filtering the data in the forward direction, the function matches initial conditions to minimize startup and ending transients, reverses the filtered sequence, and runs the reversed sequence back through the filter. The result has these characteristics:', '* Zero phase distortion', '* A filter transfer function equal to the squared magnitude of the original filter transfer function', '* A filter order that is double the order of the filter specified by b and a', 'Do not use filtfilt with differentiator and Hilbert FIR filters, because the operation of those filters depends heavily on their phase response.'] },
    cconv: { summary: 'Circularly convolves vectors a and b.', syntax: ['c = cconv(a,b)', 'c = cconv(a,b,n)'], seealso: ['conv', 'xcorr'], description: ['c = cconv(a,b) circularly convolves vectors a and b.', 'c = cconv(a,b,n) circularly convolves vectors a and b. n is the length of the resulting vector. You can also use cconv to compute the circular cross-correlation of two sequences.'] },
    fftfilt: { summary: 'FIR filter b applied to x via overlap-add FFT; result equals filter(b,1,x) to ~1e-10.', syntax: ['y = fftfilt(b,x)', 'y = fftfilt(b,x,nfft)'], seealso: ['filter', 'filtfilt', 'upfirdn'], description: ['y = fftfilt(b,x) filters the data specified in vector x. The function uses the filter described by the coefficient vector b.', 'y = fftfilt(b,x,nfft) uses nfft to determine the length of the FFT.', 'y = fftfilt(d,x) filters the data in vector x with a digitalFilter object d.', 'y = fftfilt(d,x,nfft) uses nfft to determine the length of the FFT.'] },
    phasez: { summary: 'Unwrapped phase response of digital filter B/A over n points in [0,pi).', syntax: ['[phi,w] = phasez(b,a)', '[phi,w] = phasez(b,a,n)'], seealso: ['freqz', 'phasedelay', 'zerophase'], description: ['[phi,w] = phasez(b,a,n) returns the phase response of the specified digital filter. Specify a digital filter with numerator coefficients b and denominator coefficients a. The function returns the n-point phase response vector in phi and the corresponding angular frequency vector w.', '[phi,w] = phasez(B,A,"ctf",n) returns the n-point phase response of the digital filter represented as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A._(since R2024b)_', '[phi,w] = phasez({B,A,g},"ctf",n) returns the n-point phase response of the digital filter in CTF format. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', '[phi,w] = phasez(d,n) returns the n-point phase response for the digital filter d.', '[phi,w] = phasez(sos,n) returns the n-point phase response corresponding to the second-order sections matrix sos.'] },
    phasedelay: { summary: 'Phase delay -angle(H(e^jw))/w of digital filter B/A over n points.', syntax: ['[phi,w] = phasedelay(b,a)', '[phi,w] = phasedelay(b,a,n)'], seealso: ['grpdelay', 'phasez', 'freqz'], description: ['[phi,w] = phasedelay(b,a,n) returns the phase delay response of the specified digital filter. Specify a digital filter with numerator coefficients b and denominator coefficients a. The function returns the n-point phase delay response vector in phi and the corresponding angular frequency vector w.', '[phi,w] = phasedelay(B,A,"ctf",n) returns the n-point phase delay response of the digital filter represented as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A._(since R2024b)_', '[phi,w] = phasedelay({B,A,g},"ctf",n) returns the n-point phase delay response of the digital filter in CTF format. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', '[phi,w] = phasedelay(d,n) returns the n-point phase delay response of the digital filter d.', '[phi,w] = phasedelay(sos,n) returns the n-point phase delay response corresponding to the second-order sections sos.'] },
    zerophase: { summary: 'Real zero-phase amplitude response of digital filter B/A over n points.', syntax: ['[Hr,w] = zerophase(b,a)', '[Hr,w] = zerophase(b,a,n)'], seealso: ['freqz', 'phasez', 'filtfilt'], description: ['[Hr,w] = zerophase(b,a) returns the zero-phase response of the specified digital filter. Specify a digital filter with numerator coefficients b and denominator coefficients a. The function evaluates the zero-phase response at 512 equally spaced points on the upper half of the unit circle, and returns the zero-phase response Hr with the corresponding angular frequencies w.', '[Hr,w] = zerophase(B,A,"ctf") returns the zero-phase response of the digital filter represented as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A._(since R2024b)_', '[Hr,w] = zerophase({B,A,g},"ctf") returns the zero-phase response of the digital filter in CTF format. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', '[Hr,w] = zerophase(d) returns the zero-phase response for the digital filter d. Use designfilt to generate d based on frequency-response specifications.', '[Hr,w] = zerophase(sos) returns the zero-phase response for the second order sections matrix sos.'] },
    zplane: { summary: 'Pole-zero plot; with row-vector inputs (b,a) computes roots; with column-vector inputs (z,p) uses them directly. Returns [z,p] in sandbox (no plot).', syntax: ['zplane(b,a)', 'zplane(z,p)', '[z,p] = zplane(b,a)'], seealso: ['freqz', 'tf2zp', 'roots'], description: ['zplane(z,p) plots the zeros and poles of discrete-time systems in the current figure window. Specify the zeros in a column vector z and the poles in a column vector p. The symbol \'o\' represents a zero and the symbol \'x\' represents a pole. The plot includes the unit circle for reference.', 'If z and p are matrices, then zplane treats each column as a separate set of poles and zeros, and plots each set in a different color.', 'zplane(b,a) first uses roots to find the zeros and poles of the transfer function represented by the numerator coefficients b and the denominator coefficients a, and then zplane plots the zeros and poles in the current figure window. Specify b and a as row vectors.', 'zplane(B,A,"ctf") finds and plots the zeros and poles of the digital filter represented as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A._(since R2024b)_', 'Note'] },
    impzlength: { summary: 'Effective impulse-response length: length(b) for FIR, or floor(log(5e-5)/log(max_pole_mag)) for IIR.', syntax: ['n = impzlength(b,a)', 'n = impzlength(b,a,tol)'], seealso: ['impz', 'filtord'], description: ['len = impzlength(b,a) returns the impulse response length of the specified filter. Specify a causal discrete-time filter with the rational system function specified by the numerator, b, and denominator, a, polynomials in _z_ –1. For stable IIR filters, len is the effective impulse response sequence length. Terms in the IIR filter’s impulse response after the len-th term are essentially zero.', 'len = impzlength(B,A,"ctf")returns the effective impulse response length for the digital filter represented as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A._(since R2024b)_', 'len = impzlength({B,A,g},"ctf") returns the effective impulse response length for the digital filter in CTF format. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', 'len = impzlength(d) returns the impulse response length for the digital filter, d. Use designfilt to generate d based on frequency-response specifications.', 'len = impzlength(sos) returns the effective impulse response length for the IIR filter specified by the second order sections matrix, sos. sos is a _K_ -by-6 matrix, where the number of sections, _K_ , must be greater than or equal to 2. If the number of sections is less than 2, impzlength considers the input to be the numerator vector, b. Each row of sos corresponds to the coefficients of a second order (biquad) filter. The _i_ th row of the sos matrix corresponds to [bi(1) bi(2) bi(3) ai(1) ai(2) ai(3)].'] },
    filtord: { summary: 'Filter order: max(degree(b), degree(a)) after trimming trailing zeros.', syntax: ['n = filtord(b,a)'], seealso: ['impzlength', 'firtype'], description: ['n = filtord(b,a) returns the filter order, n, for the specified digital filter. Specify a digital filter as a causal rational system function with numerator coefficients, b, and denominator coefficients, a.', 'n = filtord(B,A,"ctf") returns the filter order for the digital filter represented as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A._(since R2024b)_', 'n = filtord({B,A,g},"ctf") returns the filter order for the digital filter in CTF format. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', 'n = filtord(d) returns the filter order, n, for the digital filter, d. Use the function designfilt to generate d.', 'n = filtord(sos) returns the filter order for the filter specified by the second-order sections matrix, sos. sos is a _K_ -by-6 matrix. The number of sections, _K_ , must be greater than or equal to 2. Each row of sos corresponds to the coefficients of a second-order filter. The _i_ th row of the second-order section matrix corresponds to [bi(1) bi(2) bi(3) ai(1) ai(2) ai(3)].'] },
    firtype: { summary: 'Linear-phase FIR type (1–4) from symmetry and length of b.', syntax: ['type = firtype(b)'], seealso: ['islinphase', 'filtord'], description: ['t = firtype(b) determines the type, t, of an FIR filter. Specify the filter coefficients with a vector b. t can be 1, 2, 3, or 4. The filter must be real and have linear phase.', 't = firtype(d) determines the type, t, of an FIR filter, d. t can be 1, 2, 3, or 4. The filter must be real and have linear phase.'] },
    islinphase: { summary: 'True if b/a is a linear-phase FIR (a=[1], b symmetric or antisymmetric).', syntax: ['tf = islinphase(b,a)', 'tf = islinphase(b,a,tol)'], seealso: ['firtype', 'isminphase', 'isallpass'], description: ['flag = islinphase(b,a) returns a logical output equal to 1 if the specified filter is linear phase. Specify a filter with numerator coefficients b and denominator coefficients a.', 'flag = islinphase(B,A,"ctf") returns 1 if the filter specified as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A is linear phase._(since R2024b)_', 'flag = islinphase({B,A,g},"ctf") returns 1 if the filter specified in CTF format is linear phase. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', 'flag = islinphase(d) returns 1 if the digital filter d is linear phase.', 'flag = islinphase(sos) returns 1 if the filter specified by the second-order sections matrix sos is linear phase.'] },
    isminphase: { summary: 'True if all zeros and poles of B/A are strictly inside the unit circle.', syntax: ['tf = isminphase(b,a)', 'tf = isminphase(b,a,tol)'], seealso: ['islinphase', 'isallpass'], description: ['flag = isminphase(b,a) returns a logical output equal to 1 if the specified filter is minimum phase. Specify a filter with numerator coefficients b and denominator coefficients a.', 'flag = isminphase(B,A,"ctf") returns 1 if the filter specified as Cascaded Transfer Functions (CTF) with numerator coefficients B and denominator coefficients A is minimum phase._(since R2024b)_', 'flag = isminphase({B,A,g},"ctf") returns 1 if the filter specified in CTF format is minimum phase. Specify the filter with numerator coefficients B, denominator coefficients A, and scaling values g across filter sections._(since R2024b)_', 'flag = isminphase(d) returns 1 if the digital filter d is minimum phase. Use designfilt to generate d based on frequency- response specifications.', 'flag = isminphase(sos) returns 1 if the filter specified by second order sections matrix sos is minimum phase.'] },
    isallpass: { summary: 'True if B/A is an allpass filter (b = fliplr(a)/a(1) for real coefficients).', syntax: ['tf = isallpass(b,a)', 'tf = isallpass(b,a,tol)'], seealso: ['islinphase', 'isminphase'], description: ['flag = isallpass(b,a) returns a logical output equal to 1 if the specified filter is allpass. Specify a filter with numerator coefficients b and denominator coefficients a.', 'flag = isallpass(sos) returns 1 if the filter specified by the second- order sections matrix sos is allpass.', 'flag = isallpass(d) returns 1 if the digital filter d is allpass.', 'flag = isallpass(___,tol) specifies a tolerance tol to determine when two numbers are close enough to be considered equal.'] },
    tf2zpk: { summary: 'Transfer-function to zero-pole-gain: same as tf2zp.', syntax: ['[z,p,k] = tf2zpk(b,a)'], seealso: ['tf2zp', 'zpk2tf', 'sos2zp'], description: ['[z,p,k] = tf2zpk(b,a) finds the vector of zeros z, the vector of poles p, and the associated gain k from the transfer function parameters b and a. The function converts a polynomial transfer-function representation', 'H(z)=B(z)A(z)=b1+b2z−1⋯+bnz−(n−1)+bn+1z−na1+a2z−1⋯+amz−(m−1)+am+1z−m', 'of a single-input/single-output (SISO) discrete-time system to a factored transfer function form', 'H(z)=Z(z)P(z)=k(z−z1)(z−z2)⋯(z−zm)(z−p1)(z−p2)⋯(z−pn).', 'Note'] },
    sos2zp: { summary: 'Second-order-sections matrix to zeros, poles, and gain.', syntax: ['[z,p,k] = sos2zp(sos)', '[z,p,k] = sos2zp(sos,g)'], seealso: ['tf2zpk', 'zp2sos', 'sosfilt'], description: ['[z,p,k] = sos2zp(sos) returns the zeros, poles, and gain of a system whose second-order section representation is given by sos.', '[z,p,k] = sos2zp(sos,g) returns the zeros, poles, and gain of a system whose second-order section representation is given by sos with gain g.'] },
    eqtflength: { summary: 'Pad shorter of b or a with trailing zeros so they have equal length.', syntax: ['[b,a] = eqtflength(b,a)'], seealso: ['filtord', 'tf2zpk'], description: ['[b,a] = eqtflength(num,den) modifies the vector num or the vector den so that the resulting output vectors b and a have the same length. b and a represent the same discrete-time transfer function as num and den, but are of equal length.', '[b,a,n,m] = eqtflength(num,den) returns the numerator order n and the denominator order m, not including any trailing zeros.'] },
    residuez: { summary: 'Partial-fraction expansion of z-transform B(z)/A(z): H = k + sum r_i/(1-p_i*z^{-1}).', syntax: ['[r,p,k] = residuez(b,a)'], seealso: ['residue', 'tf2zpk', 'zp2tf'], description: ['Use residuez to convert from polynomial coefficients to residues, poles and direct terms, and vice versa.', '[ro,po,ko] = residuez(bi,ai) finds the residues, poles, and direct terms of a partial fraction expansion of the ratio of numerator and denominator polynomials, bi and ai.', '[bo,ao] = residuez(ri,pi,ki) converts the partial fraction expansion back to polynomials with coefficients in row vectors bo and ao.'] },
    interp: { summary: 'FIR interpolation: upsample x by integer r using a Hamming-windowed sinc lowpass filter.', syntax: ['y = interp(x,r)', 'y = interp(x,r,n)', 'y = interp(x,r,n,cutoff)'], seealso: ['decimate', 'resample', 'upsample', 'upfirdn'], description: ['y = interp(x,r) increases the sample rate of input signal x by a factor of r.', 'y = interp(x,r,n,cutoff) specifies two additional values:', '* n is half the number of original sample values used to interpolate the expanded signal.', '* cutoff is the normalized cutoff frequency of the input signal, specified as a fraction of the Nyquist frequency.', '[y,b] = interp(x,r,n,cutoff) also returns the filter coefficients used for the interpolation.'] },
    buffer: { summary: 'Partition signal vector x into non-overlapping (or overlapping) frames of length n, with optional overlap p.', syntax: ['y = buffer(x,n)', 'y = buffer(x,n,p)'], seealso: ['reshape', 'spectrogram'], description: ['y = buffer(x,n) partitions a length-L signal x into nonoverlapping data segments (frames) of length n.', 'y = buffer(x,n,p) overlaps or underlaps successive frames in the output matrix by p samples.', 'y = buffer(x,n,p,opt) specifies a vector of samples to precede x(1) in an overlapping buffer, or the number of initial samples to skip in an underlapping buffer.', '[y,z] = buffer(___) partitions a length-L signal x into frames of length n, and outputs only the full frames in y. The vector z contains the remaining samples. This syntax can include any combination of input arguments from the previous syntaxes.', '[y,z,opt] = buffer(___) returns the last p samples of an overlapping buffer in output opt.'] },
    cheb1ap: { summary: 'Returns the poles and gain of an order N Chebyshev Type I analog lowpass filter prototype with Rp dB of passband ripple.', syntax: ['[z,p,k] = cheb1ap(n,Rp)'], seealso: ['besselap', 'buttap', 'cheb2ap', 'ellipap', 'cheby1'], description: ['[z,p,k] = cheb1ap(n,Rp) returns the poles and gain of an order n Chebyshev Type I analog lowpass filter prototype with Rp dB of ripple in the passband.'] },
    cheb2ap: { summary: 'Returns the zeros, poles, and gain of an order N Chebyshev Type II analog lowpass filter prototype with Rs dB of stopband attenuation.', syntax: ['[z,p,k] = cheb2ap(n,Rs)'], seealso: ['besselap', 'buttap', 'cheb1ap', 'ellipap', 'cheby2'], description: ['[z,p,k] = cheb2ap(n,Rs) returns the zeros, poles, and gain of an order n Chebyshev Type II analog lowpass filter prototype with Rs dB of ripple down from the passband peak value in the stopband.'] },
    ellipap: { summary: 'Returns the zeros, poles, and gain of an order N elliptic analog lowpass filter prototype with Rp dB passband ripple and Rs dB stopband attenuation.', syntax: ['[z,p,k] = ellipap(n,Rp,Rs)'], seealso: ['besselap', 'buttap', 'cheb1ap', 'cheb2ap', 'ellip'], description: ['[z,p,k] = ellipap(n,Rp,Rs) returns the zeros, poles, and gain of an nth-order elliptic analog lowpass filter prototype, with Rp dB of ripple in the passband and a stopband Rs dB down from the peak value in the passband.'] },
    besselap: { summary: 'Returns the poles and gain of an order N Bessel analog lowpass filter prototype (maximally flat group delay). Supported orders: 1–10.', syntax: ['[z,p,k] = besselap(n)'], seealso: ['buttap', 'cheb1ap', 'cheb2ap', 'ellipap'], description: ['[z,p,k] = besselap(n) returns the poles p and gain k of an order-n Bessel analog lowpass filter prototype. z is an empty matrix because the prototype has no zeros.'] },
    lp2lp: { summary: 'Transforms a lowpass analog filter prototype with a cutoff frequency of 1 rad/s to a lowpass filter with a cutoff frequency of Wo rad/s.', syntax: ['[bt,at] = lp2lp(b,a,Wo)'], seealso: ['lp2hp', 'lp2bp', 'lp2bs', 'bilinear'], description: ['[bt,at] = lp2lp(b,a,Wo) transforms an analog lowpass filter prototype with unity cutoff frequency (1 rad/s) into a lowpass filter with cutoff angular frequency Wo rad/s. Specify the filter prototype with numerator coefficients b and denominator coefficients a as row vectors. The input system must be an analog filter prototype.', '[At,Bt,Ct,Dt] = lp2lp(A,B,C,D,Wo) converts the continuous- time state-space lowpass filter prototype (specified by matrices A, B, C, and D) with unity cutoff frequency (1 rad/s) to a lowpass filter with cutoff angular frequency Wo rad/s. The input system must be an analog filter prototype.'] },
    lp2hp: { summary: 'Transforms a lowpass analog filter prototype with a cutoff frequency of 1 rad/s to a highpass filter with a cutoff frequency of Wo rad/s.', syntax: ['[bt,at] = lp2hp(b,a,Wo)'], seealso: ['lp2lp', 'lp2bp', 'lp2bs', 'bilinear'], description: ['[bt,at] = lp2hp(b,a,Wo) transforms an analog lowpass filter prototype with unity cutoff frequency (1 rad/s) into a highpass analog filter with cutoff angular frequency Wo. Specify the filter prototype with numerator coefficients b and denominator coefficients a as row vectors. The input system must be an analog filter prototype.', '[At,Bt,Ct,Dt] = lp2hp(A,B,C,D,Wo) converts the continuous- time state-space lowpass filter prototype (specified by matrices A, B, C, and D) to a highpass analog filter with cutoff angular frequency Wo. The input system must be an analog filter prototype.'] },
    lp2bp: { summary: 'Transforms a lowpass analog filter prototype with a cutoff frequency of 1 rad/s to a bandpass filter with center frequency Wo rad/s and bandwidth Bw.', syntax: ['[bt,at] = lp2bp(b,a,Wo,Bw)'], seealso: ['lp2lp', 'lp2hp', 'lp2bs', 'bilinear'], description: ['[bt,at] = lp2bp(b,a,Wo,Bw) transforms an analog lowpass filter prototype with unity cutoff frequency (1 rad/s) into a bandpass filter with center frequency Wo and bandwidth Bw. Specify the filter prototype with numerator coefficients b and denominator coefficients a as row vectors. The input system must be an analog filter prototype.', '[At,Bt,Ct,Dt] = lp2bp(A,B,C,D,Wo,Bw) converts the continuous-time state-space lowpass filter prototype (specified by matrices A, B, C, and D) to a bandpass filter with center frequency Wo and bandwidth Bw. The input system must be an analog filter prototype.'] },
    lp2bs: { summary: 'Transforms a lowpass analog filter prototype with a cutoff frequency of 1 rad/s to a bandstop filter with center frequency Wo rad/s and bandwidth Bw.', syntax: ['[bt,at] = lp2bs(b,a,Wo,Bw)'], seealso: ['lp2lp', 'lp2hp', 'lp2bp', 'bilinear'], description: ['[bt,at] = lp2bs(b,a,Wo,Bw) transforms an analog lowpass filter prototype with unity cutoff frequency (1 rad/s) into a bandstop filter with center frequency Wo and bandwidth Bw. Specify the filter prototype with numerator coefficients b and denominator coefficients a as row vectors. The input system must be an analog filter prototype.', '[At,Bt,Ct,Dt] = lp2bs(A,B,C,D,Wo,Bw) converts the continuous-time state-space lowpass filter prototype (specified by matrices A, B, C, and D) to a bandstop filter with center frequency Wo and bandwidth Bw. The input system must be an analog filter prototype.'] },
    impinvar: { summary: 'Converts the analog filter with transfer function B(s)/A(s) to the digital filter B(z)/A(z) using the impulse invariance method with sample rate Fs (default 1).', syntax: ['[bz,az] = impinvar(b,a,Fs)'], seealso: ['bilinear', 'butter', 'cheby1'], description: ['[bz,az] = impinvar(b,a,fs) creates a digital filter with numerator and denominator coefficients bz and az, respectively, whose impulse response is equal to the impulse response of the analog filter with coefficients b and a, scaled by 1/fs, where fs is the sample rate.', '[bz,az] = impinvar(b,a,fs,tol) uses the tolerance specified by tol to determine whether poles are repeated.'] },
    lpc: { summary: 'Returns the linear prediction filter coefficients a and the prediction error power e for the input signal x using a p-th order forward linear predictor.', syntax: ['a = lpc(x,p)', '[a,e] = lpc(x,p)'], seealso: ['aryule', 'arburg', 'levinson', 'ac2poly'], description: ['[a,g] = lpc(x,p) finds the coefficients of a pth-order linear predictor, an FIR filter that predicts the current value of the real-valued time series x based on past samples. The function also returns g, the variance of the prediction error. If x is a matrix, the function treats each column as an independent channel.'] },
    aryule: { summary: 'Returns the AR model parameters for a given input signal x using the Yule-Walker method (autocorrelation/Levinson-Durbin).', syntax: ['a = aryule(x,p)', '[a,e,k] = aryule(x,p)'], seealso: ['arburg', 'arcov', 'armcov', 'lpc'], description: ['a = aryule(x,p) returns the normalized autoregressive (AR) parameters corresponding to a model of order p for the input array x.', '[a,e] = aryule(x,p) also returns the estimated variance, e, of the white noise input associated with the autoregressive model.', '[a,e,rc] = aryule(x,p) also returns the reflection coefficients, rc, associated with the autoregressive model.'] },
    arburg: { summary: 'Returns the AR model parameters for a given input signal x using the Burg method.', syntax: ['a = arburg(x,p)', '[a,e,k] = arburg(x,p)'], seealso: ['aryule', 'arcov', 'armcov', 'lpc'], description: ['a = arburg(x,p) returns the normalized autoregressive (AR) parameters corresponding to a model of order p for the input array x.', '[a,e] = arburg(x,p) also returns the estimated variance, e, of the white noise input associated with the autoregressive model.', '[a,e,rc] = arburg(x,p) also returns the reflection coefficients, rc, associated with the autoregressive model.'] },
    arcov: { summary: 'Returns the AR model parameters for a given input signal x using the covariance method.', syntax: ['a = arcov(x,p)', '[a,e] = arcov(x,p)'], seealso: ['arburg', 'aryule', 'armcov', 'lpc'], description: ['a = arcov(x,p) returns the normalized autoregressive (AR) parameters corresponding to a model of order p for the input array x, where x is assumed to be the output of an AR system driven by white noise. This method minimizes the forward prediction error in the least-squares sense.', '[a,e] = arcov(x,p) also returns the estimated variance, e, of the white noise input.'] },
    armcov: { summary: 'Returns the AR model parameters for a given input signal x using the modified covariance method.', syntax: ['a = armcov(x,p)', '[a,e] = armcov(x,p)'], seealso: ['arburg', 'arcov', 'aryule', 'lpc'], description: ['a = armcov(x,p) returns the normalized autoregressive (AR) parameters corresponding to a model of order p for the input array x. x is assumed to be the output of an AR system driven by white noise. This method minimizes the forward and backward prediction errors in the least-squares sense.', '[a,e] = armcov(x,p) also returns the estimated variance, e, of the white noise input.'] },
    snr: { summary: 'Returns the signal-to-noise ratio (SNR) in decibels of the fundamental signal component relative to all other spectral components.', syntax: ['r = snr(x)', 'r = snr(x,Fs)'], seealso: ['sinad', 'thd', 'sfdr'], description: ['r = snr(xi,y) returns the signal-to-noise ratio (SNR) in decibels of a signal xi by computing the ratio of its summed squared magnitude to that of the noise y:', 'r = mag2db(rssq(xi(:))/rssq(y(:))).', 'y must have the same dimensions as xi. Use this form when the input signal is not necessarily sinusoidal and you have an estimate of the noise.', 'r = snr(x) returns the SNR in decibels relative to the carrier (dBc) of a real-valued sinusoidal input signal x. The SNR is determined using a modified periodogram of the same length as the input. The modified periodogram uses a Kaiser window with _β_ = 38. The result excludes the power of the first six harmonics, including the fundamental.', 'r = snr(x,fs,n) returns the SNR in dBc of a real sinusoidal input signal x sampled at a rate fs. The computation excludes the power contained in the lowest n harmonics, including the fundamental.'] },
    sinad: { summary: 'Returns the signal-to-noise-and-distortion ratio (SINAD) in decibels of the fundamental signal component relative to all other spectral components including harmonics.', syntax: ['r = sinad(x)', 'r = sinad(x,Fs)'], seealso: ['snr', 'thd', 'sfdr'], description: ['r = sinad(x) returns the signal to noise and distortion ratio (SINAD) in dBc of the real-valued sinusoidal signal x. The SINAD is determined using a modified periodogram of the same length as the input signal. The modified periodogram uses a Kaiser window with _β_ = 38.', 'r = sinad(x,Fs) specifies the sample rate Fs of the input signal x. If you do not specify Fs, then the sample rate defaults to 1.', 'r = sinad(pxx,f,"psd") specifies the input pxx as a one-sided power spectral density (PSD) estimate. f is a vector of frequencies corresponding to the PSD estimates in pxx.', 'r = sinad(sxx,f,rbw,"power") specifies the input as a one-sided power spectrum. rbw is the resolution bandwidth over which each power estimate is integrated.', '[r,totdistpow] = sinad(___) returns the total noise and harmonic distortion power (in dB) of the signal.'] },
    thd: { summary: 'Returns the total harmonic distortion (THD) in decibels of the first n harmonics relative to the fundamental.', syntax: ['r = thd(x)', 'r = thd(x,Fs)', 'r = thd(x,Fs,n)'], seealso: ['snr', 'sinad', 'sfdr'], description: ['r = thd(x) returns the total harmonic distortion (THD) in dBc of the real-valued sinusoidal signal x. The total harmonic distortion is determined from the fundamental frequency and the first five harmonics using a modified periodogram of the same length as the input signal. The modified periodogram uses a Kaiser window with _β_ = 38.', 'r = thd(x,Fs,n) specifies the sample rate Fs and the number of harmonics (including the fundamental) to use in the THD calculation.', 'r = thd(pxx,f,"psd") specifies the input pxx as a one-sided power spectral density (PSD) estimate. f is a vector of frequencies corresponding to the PSD estimates in pxx.', 'r = thd(pxx,f,n,"psd") specifies the number of harmonics (including the fundamental) to use in the THD calculation.', 'r = thd(sxx,f,rbw,"power") specifies the input as a one-sided power spectrum. rbw is the resolution bandwidth over which each power estimate is integrated.'] },
    sfdr: { summary: 'Returns the spurious-free dynamic range (SFDR) in decibels, the ratio of the fundamental component to the largest spurious spectral component.', syntax: ['r = sfdr(x)', 'r = sfdr(x,Fs)'], seealso: ['snr', 'sinad', 'thd'], description: ['r = sfdr(x) returns the spurious free dynamic range (SFDR), r, in dB of the real sinusoidal signal, x. sfdr computes the power spectrum using a modified periodogram and a Kaiser window with _β_ = 38. The mean is subtracted from x before computing the power spectrum. The number of points used in the computation of the discrete Fourier transform (DFT) is the same as the length of the signal, x.', 'r = sfdr(x,fs) returns the SFDR of the time-domain input signal, x, when the sample rate, fs, is specified. The default value of fs is 1 Hz.', 'r = sfdr(x,fs,msd) returns the SFDR considering only spurs that are separated from the fundamental (carrier) frequency by the minimum spur distance, msd, specified in cycles/unit time. The sample rate is fs. If the carrier frequency is Fc, then all spurs in the interval (Fc-msd, Fc+msd) are ignored.', 'r = sfdr(sxx,f,\'power\') returns the SFDR of the one-sided power spectrum of a real-valued signal, sxx. f is the vector of frequencies corresponding to the power estimates in sxx. The first element of f must equal 0. The algorithm removes all the power that decreases monotonically away from the DC bin.', 'r = sfdr(sxx,f,msd,\'power\') returns the SFDR considering only spurs that are separated from the fundamental (carrier) frequency by the minimum spur distance, msd. If the carrier frequency is Fc, then all spurs in the interval (Fc-msd, Fc+msd) are ignored. When the input to sfdr is a power spectrum, specifying msd can prevent high sidelobe levels from being identified as spurs.'] },
    pburg: { summary: 'Estimates the power spectral density of x using the Burg method, returning the PSD pxx and corresponding frequency vector w (in rad/sample).', syntax: ['[pxx,w] = pburg(x,order)', '[pxx,w] = pburg(x,order,nfft)'], seealso: ['pyulear', 'pcov', 'pmcov', 'pwelch', 'periodogram'], description: ['pxx = pburg(x,order) returns the power spectral density (PSD) estimate, pxx, of a discrete-time signal, x, found using Burg’s method. When x is a vector, it is treated as a single channel. When x is a matrix, the PSD is computed independently for each column and stored in the corresponding column of pxx. pxx is the distribution of power per unit frequency. The frequency is expressed in units of rad/sample. order is the order of the autoregressive (AR) model used to produce the PSD estimate.', 'pxx = pburg(x,order,nfft) uses nfft points in the discrete Fourier transform (DFT). For real x, pxx has length (nfft/2+1) if nfft is even, and (nfft+1)/2 if nfft is odd. For complex–valued x, pxx always has length nfft. If you omit nfft, or specify it as empty, then pburg uses a default DFT length of 256.', 'pxx,[w] = pburg(___) returns the vector of normalized angular frequencies, w, at which the PSD is estimated. w has units of rad/sample. For real-valued signals, w spans the interval [0,_π_] when nfft is even and [0,_π_) when nfft is odd. For complex-valued signals, w always spans the interval [0,2 _π_).', 'pxx,[f] = pburg(___,Fs) returns a frequency vector, f, in cycles per unit time. The sample rate, Fs, is the number of samples per unit time. If the unit of time is seconds, then f is in cycles/second (Hz). For real-valued signals, f spans the interval [0,Fs/2] when nfft is even and [0,Fs/2) when nfft is odd. For complex-valued signals, f spans the interval [0,Fs). Fs must be the fourth input to pburg. To input a sample rate and still use the default values of the preceding optional arguments, specify these arguments as empty, [].', 'pxx,[w] = pburg(x,order,w) returns the two-sided AR PSD estimates at the normalized frequencies specified in the vector, w. The vector w must contain at least two elements, because otherwise the function interprets it as nfft.'] },
    pyulear: { summary: 'Estimates the power spectral density of x using the Yule-Walker (autocorrelation) AR method.', syntax: ['[pxx,w] = pyulear(x,order)', '[pxx,w] = pyulear(x,order,nfft)'], seealso: ['pburg', 'pcov', 'pmcov', 'pwelch'], description: ['pxx = pyulear(x,order) returns the power spectral density estimate, pxx, of a discrete-time signal, x, found using the Yule-Walker method. When x is a vector, it is treated as a single channel. When x is a matrix, the PSD is computed independently for each column and stored in the corresponding column of pxx. pxx is the distribution of power per unit frequency. The frequency is expressed in units of rad/sample. order is the order of the autoregressive (AR) model used to produce the PSD estimate.', 'pxx = pyulear(x,order,nfft) uses nfft points in the discrete Fourier transform (DFT). For real x, pxx has length (nfft/2 + 1) if nfft is even, and (nfft \\+ 1)/2 if nfft is odd. For complex-valued x, pxx always has length nfft. If you omit nfft, or specify it as empty, then pyulear uses a default DFT length of 256.', 'pxx,[w] = pyulear(___) returns the vector of normalized angular frequencies, w, at which the PSD is estimated. w has units of rad/sample. For real-valued signals, w spans the interval [0,_π_] when nfft is even and [0,_π_) when nfft is odd. For complex-valued signals, w always spans the interval [0,2 _π_).', 'pxx,[f] = pyulear(___,Fs) returns a frequency vector, f, in cycles per unit time. The sample rate, Fs, is the number of samples per unit time. If the unit of time is seconds, then f is in cycles/second (Hz). For real–valued signals, f spans the interval [0,Fs/2] when nfft is even and [0,Fs/2) when nfft is odd. For complex-valued signals, f spans the interval [0,Fs). Fs must be the fourth input to pyulear. To input a sample rate and still use the default values of the preceding optional arguments, specify these arguments as empty, [].', 'pxx,[w] = pyulear(x,order,w) returns the two-sided AR PSD estimates at the normalized frequencies specified in the vector, w. The vector, w, must contain at least two elements, because otherwise the function interprets it as nfft.'] },
    pcov: { summary: 'Estimates the power spectral density of x using the covariance AR method (forward prediction error minimization).', syntax: ['[pxx,w] = pcov(x,order)', '[pxx,w] = pcov(x,order,nfft)'], seealso: ['pburg', 'pyulear', 'pmcov'], description: ['pxx = pcov(x,order) returns the power spectral density (PSD) estimate, pxx, of a discrete-time signal, x, found using the covariance method. When x is a vector, it is treated as a single channel. When x is a matrix, the PSD is computed independently for each column and stored in the corresponding column of pxx. pxx is the distribution of power per unit frequency. The frequency is expressed in units of rad/sample. order is the order of the autoregressive (AR) model used to produce the PSD estimate.', 'pxx = pcov(x,order,nfft) uses nfft points in the discrete Fourier transform (DFT). For real x, pxx has length (nfft/2+1) if nfft is even, and (nfft+1)/2 if nfft is odd. For complex–valued x, pxx always has length nfft. If you omit nfft, or specify it as empty, then pcov uses a default DFT length of 256.', 'pxx,[w] = pcov(___) returns the vector of normalized angular frequencies, w, at which the PSD is estimated. w has units of radians/sample. For real-valued signals, w spans the interval [0, _π_] when nfft is even and [0,_π_) when nfft is odd. For complex–valued signals, w always spans the interval [0,2 _π_].', 'pxx,[f] = pcov(___,Fs) returns a frequency vector, f, in cycles per unit time. The sample rate, Fs, is the number of samples per unit time. If the unit of time is seconds, then f is in cycles/second (Hz). For real-valued signals, f spans the interval [0,Fs/2] when nfft is even and [0,Fs/2) when nfft is odd. For complex-valued signals, f spans the interval [0,Fs). Fs must be the fourth input to pcov. To input a sample rate and still use the default values of the preceding optional arguments, specify these arguments as empty, [].', 'pxx,[w] = pcov(x,order,w) returns the two-sided AR PSD estimates at the normalized frequencies specified in the vector, w. The vector w must contain at least two elements, because otherwise the function interprets it as nfft.'] },
    pmcov: { summary: 'Estimates the power spectral density of x using the modified covariance AR method (average of forward and backward prediction errors).', syntax: ['[pxx,w] = pmcov(x,order)', '[pxx,w] = pmcov(x,order,nfft)'], seealso: ['pburg', 'pyulear', 'pcov'], description: ['pxx = pmcov(x,order) returns the power spectral density estimate, pxx, of a discrete-time signal, x, found using the modified covariance method. When x is a vector, it is treated as a single channel. When x is a matrix, the PSD is computed independently for each column and stored in the corresponding column of pxx. pxx is the distribution of power per unit frequency. The frequency is expressed in units of rad/sample. order is the order of the autoregressive (AR) model used to produce the PSD estimate.', 'pxx = pmcov(x,order,nfft) uses nfft points in the discrete Fourier transform (DFT). For real x, pxx has length (nfft/2+1) if nfft is even, and (nfft+1)/2 if nfft is odd. For complex–valued x, pxx always has length nfft. If you omit nfft, or specify it as empty, then pmcov uses a default DFT length of 256.', 'pxx,[w] = pmcov(___) returns the vector of normalized angular frequencies, w, at which the PSD is estimated. w has units of rad/sample. For real–valued signals, w spans the interval [0,_π_] when nfft is even and [0,_π_) when nfft is odd. For complex–valued signals, w always spans the interval [0,2 _π_).', 'pxx,[f] = pmcov(___,Fs) returns a frequency vector, f, in cycles per unit time. The sample rate, Fs, is the number of samples per unit time. If the unit of time is seconds, then f is in cycles/second (Hz). For real-valued signals, f spans the interval [0,Fs/2] when nfft is even and [0,Fs/2) when nfft is odd. For complex-valued signals, f spans the interval [0,Fs). Fs must be the fourth input to pmcov. To input a sample rate and still use the default values of the preceding optional arguments, specify these arguments as empty, [].', 'pxx,[w] = pmcov(x,order,w) returns the two-sided AR PSD estimates at the normalized frequencies specified in the vector, w. The vector w must contain at least two elements, because otherwise the function interprets it as nfft.'] },
    cpsd: { summary: 'Estimates the cross power spectral density of signals x and y using Welch\'s averaged, modified periodogram method.', syntax: ['[pxy,f] = cpsd(x,y)', '[pxy,f] = cpsd(x,y,window,noverlap,nfft,fs)'], seealso: ['mscohere', 'tfestimate', 'pwelch'], description: ['pxy = cpsd(x,y) estimates the Cross Power Spectral Density (CPSD) of two discrete-time signals, x and y, using Welch’s averaged, modified periodogram method of spectral estimation.', '* If x and y are both vectors, they must have the same length.', '* If one of the signals is a matrix and the other is a vector, then the length of the vector must equal the number of rows in the matrix. The function expands the vector and returns a matrix of column-by-column CPSD estimates.', '* If x and y are matrices with the same number of rows but different numbers of columns, then cpsd returns a three-dimensional array, pxy, containing CPSD estimates for all combinations of input columns. Each column of pxy corresponds to a column of x, and each page corresponds to a column of y: pxy(:,m,n) = cpsd(x(:,m),y(:,n)).', '* If x and y are matrices of equal size, then cpsd operates column-wise: pxy(:,n) = cpsd(x(:,n),y(:,n)). To obtain a multi-input/multi-output array, append "mimo" to the argument list.'] },
    mscohere: { summary: 'Estimates the magnitude-squared coherence of signals x and y using Welch\'s overlapped averaged periodogram method.', syntax: ['[cxy,f] = mscohere(x,y)', '[cxy,f] = mscohere(x,y,window,noverlap,nfft,fs)'], seealso: ['cpsd', 'tfestimate', 'pwelch'], description: ['cxy = mscohere(x,y) finds the magnitude-squared coherence estimate, cxy, of the input signals, x and y.', '* If x and y are both vectors, they must have the same length.', '* If one of the signals is a matrix and the other is a vector, then the length of the vector must equal the number of rows in the matrix. The function expands the vector and returns a matrix of column-by-column magnitude-squared coherence estimates.', '* If x and y are matrices with the same number of rows but different numbers of columns, then mscohere returns a multiple coherence matrix. The _m_ th column of cxy contains an estimate of the degree of correlation between all the input signals and the _m_ th output signal. See Magnitude-Squared Coherence for more information.', '* If x and y are matrices of equal size, then mscohere operates column-wise: cxy(:,n) = mscohere(x(:,n),y(:,n)). To obtain a multiple coherence matrix, append "mimo" to the argument list.'] },
    tfestimate: { summary: 'Estimates the transfer function H(f) = Pxy(f)/Pxx(f) between input x and output y using the Welch H1 method.', syntax: ['[txy,f] = tfestimate(x,y)', '[txy,f] = tfestimate(x,y,window,noverlap,nfft,fs)'], seealso: ['cpsd', 'mscohere', 'pwelch'], description: ['txy = tfestimate(x,y) finds a transfer function estimate between the input signal x and the output signal y evaluated at a set of frequencies.', '* If x and y are both vectors, they must have the same length.', '* If one of the signals is a matrix and the other is a vector, then the length of the vector must equal the number of rows in the matrix. The function expands the vector and returns a matrix of column-by-column transfer function estimates.', '* If x and y are matrices with the same number of rows but different numbers of columns, then txy is a multi-input/multi-output (MIMO) transfer function that combines all input and output signals. txy is a three-dimensional array. If x has _m_ columns and y has _n_ columns, then txy has _n_ columns and _m_ pages. See Transfer Function for more information.', '* If x and y are matrices of equal size, then tfestimate operates column-wise: txy(:,n) = tfestimate(x(:,n),y(:,n)). To obtain a MIMO estimate, append "mimo" to the argument list.'] },
    plomb: { summary: 'Computes the Lomb-Scargle periodogram of signal x sampled at times t (possibly nonuniform).', syntax: ['[pxx,f] = plomb(x,t)', '[pxx,f] = plomb(x,t,fvec)'], seealso: ['periodogram', 'pwelch', 'pburg'], description: ['[pxx,f] = plomb(x,t) returns the Lomb-Scargle power spectral density (PSD) estimate, pxx, of a signal, x, that is sampled at the instants specified in t. t must increase monotonically but need not be uniformly spaced. All elements of t must be nonnegative. pxx is evaluated at the frequencies returned in f.', '* If x is a vector, it is treated as a single channel.', '* If x is a matrix, then plomb computes the PSD independently for each column and returns it in the corresponding column of pxx.', 'x or t can contain NaNs or NaTs. These values are treated as missing data and excluded from the spectrum computation.', '[pxx,f] = plomb(x,fs) treats the case where the signal is sampled uniformly, at a rate fs, but has missing samples. Specify the missing data using NaNs.'] },
    rcosdesign: { summary: 'Designs a raised-cosine (normal) or root-raised-cosine (sqrt) FIR pulse-shaping filter of length span*sps+1, normalized to unit energy.', syntax: ['b = rcosdesign(beta,span,sps)', 'b = rcosdesign(beta,span,sps,shape)'], seealso: ['gaussdesign', 'fir1', 'fir2'], description: ['b = rcosdesign(beta,span,sps) returns the coefficients b that correspond to a square-root raised cosine FIR filter with rolloff factor specified by beta. The filter is truncated to span symbols, and each symbol period contains sps samples. The order of the filter, sps*span, must be even. The filter energy is 1.', 'b = rcosdesign(beta,span,sps,shape) returns a square-root raised cosine filter when you set shape to "sqrt" and a normal raised cosine FIR filter when you set shape to "normal".'] },
    gaussdesign: { summary: 'Designs a Gaussian FIR pulse-shaping filter with BT product bt, symbol span span, and sps samples per symbol.', syntax: ['h = gaussdesign(bt,span,sps)'], seealso: ['rcosdesign', 'fir1'], description: ['h = gaussdesign(bt,span,sps) designs a lowpass FIR Gaussian pulse- shaping filter and returns a vector h of filter coefficients. The filter is truncated to span symbols, and each symbol period contains sps samples. The order of the filter, sps*span, must be even.'] },
    invfreqz: { summary: 'Identifies a digital IIR filter [b,a] by least-squares fitting to complex frequency response samples h at angular frequencies w.', syntax: ['[b,a] = invfreqz(h,w,nb,na)'], seealso: ['freqz', 'invfreqs', 'prony', 'stmcb'], description: ['[b,a] = invfreqz(h,w,n,m) returns the real numerator and denominator coefficient vectors b and a of the transfer function h.', '[b,a] = invfreqz(h,w,n,m,wt) weights the fit-errors versus frequency using wt.', '[b,a] = invfreqz(___,iter) provides an algorithm that guarantees stability of the resulting linear system by searching for the best fit using a numerical, iterative scheme. This syntax can include any combination of input arguments from the previous syntaxes.', '[b,a] = invfreqz(___,tol) uses tol to decide convergence of the iterative algorithm.', '[b,a] = invfreqz(___,\'trace\') displays a textual progress report of the iteration.'] },
    prony: { summary: 'Uses Prony\'s method to fit an IIR transfer function [b,a] of orders nb and na to the impulse response sequence h.', syntax: ['[b,a] = prony(h,nb,na)'], seealso: ['invfreqz', 'stmcb', 'levinson'], description: ['[b,a] = prony(h,bord,aord) returns the numerator and denominator coefficients for a causal rational transfer function with impulse response h, numerator order bord, and denominator order aord.'] },
    stmcb: { summary: 'Uses the iterative Steiglitz-McBride method to fit an IIR transfer function [b,a] of orders nb and na to the impulse response h.', syntax: ['[b,a] = stmcb(h,nb,na)', '[b,a] = stmcb(h,nb,na,niter)'], seealso: ['prony', 'invfreqz', 'levinson'], description: ['[b,a] = stmcb(h,nb,na) finds the coefficients b and a of the system _b_(_z_)/_a_(_z_) with approximate impulse response h, exactly nb zeros, and exactly na poles.', '[b,a] = stmcb(h,nb,na,niter) uses niter iterations. The default number of iterations is 5.', '[b,a] = stmcb(h,nb,na,niter,ai) uses the vector ai as the initial estimate of the denominator coefficients.', '[b,a] = stmcb(y,x,___) finds the coefficients with system output y and input x replacing h. y and x must be the same length.'] },
    tf2latc: { summary: 'Converts a digital transfer function [b,a] to lattice or lattice-ladder form, returning reflection coefficients K (and optional ladder coefficients V).', syntax: ['K = tf2latc(b,a)', '[K,V] = tf2latc(b,a)'], seealso: ['latc2tf', 'latcfilt', 'poly2rc', 'rc2poly'], description: ['[k,v] = tf2latc(b,a) returns the lattice coefficients k and the ladder coefficients v for an IIR (ARMA) lattice-ladder filter, normalized by a(1). The function errors if one or more of the lattice coefficients are exactly equal to 1.', '[k,v] = tf2latc(b0,a) returns the ladder coefficients where only the first element in v is nonzero. b0 is a scalar.', 'k = tf2latc(1,a) returns the lattice coefficients k for an IIR all- pole (AR) lattice filter.', 'k = tf2latc(b) returns the lattice coefficients k for an FIR (MA) lattice filter, normalized by b(1).', 'k = tf2latc(b,phase) specifies the type of FIR (MA) lattice filter as minimum-phase or maximum-phase.'] },
    latc2tf: { summary: 'Converts lattice filter coefficients K (and optional ladder coefficients V) back to a transfer function [b,a].', syntax: ['[b,a] = latc2tf(K)', '[b,a] = latc2tf(K,V)'], seealso: ['tf2latc', 'latcfilt', 'rc2poly'], description: ['[b,a] = latc2tf(k,v) returns the transfer function coefficients b and a corresponding to the IIR lattice-ladder filter specified by lattice coefficients k and ladder coefficients v.', '[b,a] = latc2tf(k,iiroption) specifies the option to generate an all-pole IIR filter transfer function or an allpass IIR filter transfer function.', 'b = latc2tf(k,firoption) specifies the option to generate a minimum- phase FIR filter, a maximum-phase FIR filter, or a general FIR filter.'] },
    latcfilt: { summary: 'Filters signal x using the lattice structure defined by reflection coefficients K (and optional ladder V for IIR), returning the forward output f and backward output g.', syntax: ['[f,g] = latcfilt(K,x)', '[f,g] = latcfilt(K,V,x)'], seealso: ['tf2latc', 'latc2tf', 'filter'], description: ['[f,g] = latcfilt(k,x) filters input signal x with the FIR lattice coefficients specified by k and returns the forward lattice filter result f and backward filter result g.', '[f,g] = latcfilt(k,v,x) filters input signal x with the IIR lattice coefficients specified by k and ladder coefficients specified by v. Both k and v must be vectors, while x can be a matrix.', '[f,g] = latcfilt(k,1,x) filters input signal x with the IIR lattice coefficients specified by k and returns the all-pole lattice filter result f and the allpass filter result g.', '[f,g,zf] = latcfilt(___,"ic",zi) specifies the initial conditions of the lattice states zi and returns the final conditions of the lattice states zf.', '[f,g,zf] = latcfilt(___,dim) filters x along the dimension dim.'] },
  };
